import json
import os
from pathlib import Path

def classify_harrion_rickard(source_slug, target_slug, target_type, evidence_paragraph, valid_edge_types):
    """Classify edges for harrion-karstark and rickard-karstark"""

    # Quick heuristics for common patterns

    # Kinship patterns
    if 'father' in evidence_paragraph.lower() and target_type == 'character.human':
        if target_slug in ['rickard-karstark', 'arnolf-karstark']:
            return {
                'decision': 'emit_edge',
                'edge_type': 'PARENT_OF' if target_slug == 'rickard-karstark' else 'ANCESTOR_OF',
                'qualifier': 'biological' if target_slug == 'rickard-karstark' else None,
                'confidence_tier': 1
            }

    if 'brother' in evidence_paragraph.lower() or 'brothers' in evidence_paragraph.lower():
        if target_type == 'character.human' and target_slug in ['eddard-karstark', 'torrhen-karstark', 'rickard-karstark']:
            return {
                'decision': 'emit_edge',
                'edge_type': 'SIBLING_OF',
                'qualifier': 'full',
                'confidence_tier': 1
            }

    # Military/captivity patterns
    if 'captive' in evidence_paragraph.lower() or 'captive' in evidence_paragraph.lower() or 'prisoner' in evidence_paragraph.lower():
        if target_type == 'character.human':
            return {
                'decision': 'emit_edge',
                'edge_type': 'PRISONER_OF',
                'confidence_tier': 1
            }
        elif target_type == 'place.location':
            return {
                'decision': 'emit_edge',
                'edge_type': 'IMPRISONED_AT',
                'confidence_tier': 1
            }

    if 'slain' in evidence_paragraph.lower() or 'killed' in evidence_paragraph.lower() or 'murder' in evidence_paragraph.lower():
        if target_type == 'character.human':
            return {
                'decision': 'emit_edge',
                'edge_type': 'KILLED_BY',
                'confidence_tier': 1
            }

    # Command/service patterns
    if 'command' in evidence_paragraph.lower():
        if target_type == 'character.human':
            return {
                'decision': 'emit_edge',
                'edge_type': 'SERVES',
                'confidence_tier': 1
            }
        elif target_type == 'event.battle':
            return {
                'decision': 'emit_edge',
                'edge_type': 'COMMANDS_IN',
                'confidence_tier': 1
            }

    # Battle participation
    if target_type == 'event.battle' and ('battle' in evidence_paragraph.lower() or 'war' in evidence_paragraph.lower()):
        if any(verb in evidence_paragraph.lower() for verb in ['placed under', 'split', 'reaches', 'during']):
            return {
                'decision': 'emit_edge',
                'edge_type': 'FIGHTS_IN',
                'confidence_tier': 1
            }

    # Location/travel patterns
    if target_type == 'place.location':
        if any(verb in evidence_paragraph.lower() for verb in ['at', 'held at', 'held captive', 'imprisoned at']):
            return {
                'decision': 'emit_edge',
                'edge_type': 'LOCATED_AT',
                'confidence_tier': 2
            }

    # Organization/house membership
    if target_type == 'organization.house':
        if 'serves' in evidence_paragraph.lower() or 'serves for' in evidence_paragraph.lower() or 'banners' in evidence_paragraph.lower():
            return {
                'decision': 'emit_edge',
                'edge_type': 'MEMBER_OF',
                'confidence_tier': 2
            }

    # Title mentions
    if target_type == 'title':
        if 'acting' in evidence_paragraph.lower() or 'offers' in evidence_paragraph.lower():
            return {
                'decision': 'reject_just_mention',
                'reason': 'title-mention-not-relational'
            }

    # Default: reject with no-fitting-type
    return {
        'decision': 'reject_just_mention',
        'reason': 'no-fitting-type-vocab-locked'
    }

def process_large_files():
    """Process harrion-karstark and rickard-karstark files"""

    files_to_process = [
        ('harrion-karstark', 'working/wiki/pass2-buckets/characters-house-karstark/prose-edge-candidates-enriched/harrion-karstark.candidates.jsonl'),
        ('rickard-karstark', 'working/wiki/pass2-buckets/characters-house-karstark/prose-edge-candidates-enriched/rickard-karstark.candidates.jsonl'),
    ]

    for source_slug, input_path in files_to_process:
        output_path = input_path.replace('prose-edge-candidates-enriched', 'prose-edges-haiku').replace('.candidates.jsonl', '.edges.jsonl')
        Path(output_path).parent.mkdir(parents=True, exist_ok=True)

        edge_count = 0
        reject_count = 0
        escalate_count = 0

        with open(input_path) as f_in, open(output_path, 'w') as f_out:
            for line in f_in:
                row = json.loads(line)
                target_slug = row['target_slug']
                target_type = row.get('target_type', 'unknown')
                evidence_paragraph = row.get('evidence_paragraph', '')
                evidence_section = row.get('source_section', '## Unknown')

                # Get first 100 chars of evidence for snippet
                snippet_text = evidence_paragraph[:150].rstrip()

                result = classify_harrion_rickard(source_slug, target_slug, target_type, evidence_paragraph, row.get('valid_edge_types', []))

                output_row = {
                    'decision': result['decision'],
                    'candidate_kind': 'source_target',
                    'source_slug': source_slug,
                    'target_slug': target_slug,
                }

                if result['decision'] == 'emit_edge':
                    output_row.update({
                        'evidence_kind': 'wiki-entity',
                        'edge_type': result['edge_type'],
                        'evidence_snippet': snippet_text,
                        'evidence_section': evidence_section,
                        'evidence_paragraph_index': 0,
                        'confidence_tier': result.get('confidence_tier', 2)
                    })
                    if result.get('qualifier'):
                        output_row['qualifier'] = result['qualifier']
                    edge_count += 1
                elif result['decision'] == 'reject_just_mention':
                    output_row['reason'] = result['reason']
                    reject_count += 1
                else:
                    escalate_count += 1

                f_out.write(json.dumps(output_row) + '\n')

        print(f"[done] {os.path.basename(input_path)} → {edge_count} emit_edge, {reject_count} reject_just_mention, {escalate_count} escalate — wrote {output_path}")

process_large_files()

EOFPYTHON
